import { attachChannelToResult } from "openclaw/plugin-sdk/channel-send-result";
import { createChatChannelPlugin, type ChannelPlugin } from "openclaw/plugin-sdk/core";

// PulseBoard is a fictional bulletin board messaging platform.
// This plugin provides stub adapters for the channel contract.

export const pulseBoardPlugin: ChannelPlugin = createChatChannelPlugin({
  base: {
    id: "pulseboard",
    meta: {
      id: "pulseboard",
      label: "PulseBoard",
      selectionLabel: "PulseBoard (Bulletin)",
      docsPath: "/channels/pulseboard",
      docsLabel: "pulseboard",
      blurb: "Real-time bulletin board messaging with boards and direct messages.",
      order: 200,
    },
    capabilities: {
      chatTypes: ["direct", "group"],
      media: false,
    },
    reload: { configPrefixes: ["channels.pulseboard"] },
    config: {
      scopedChannelConfig: () => ({}),
      listAccountIds: () => [],
      defaultAccountId: () => "default",
      resolveAccount: () => ({ accountId: "default" }),
      isConfigured: () => false,
      describeAccount: () => ({ accountId: "default", configured: false }),
    },
    setup: {
      applyAccountConfig: async () => ({}),
    },
    messaging: {
      normalizeTarget: (target) => target.trim(),
    },
    gateway: {
      startAccount: async (ctx) => {
        ctx.log?.info(`[${ctx.account?.accountId ?? "default"}] starting PulseBoard provider`);
        return {
          stop: () => {
            ctx.log?.info(
              `[${ctx.account?.accountId ?? "default"}] PulseBoard provider stopped`,
            );
          },
        };
      },
    },
  },
  outbound: {
    deliveryMode: "direct",
    textChunkLimit: 4000,
    sendText: async ({ to }) => {
      return attachChannelToResult("pulseboard", {
        to,
        messageId: `pb-${Date.now()}`,
      });
    },
  },
});

